from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["ia-operator-bridge-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>IA Operator Bridge</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button,input,textarea{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:90px}.item{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px}.wait{border-left-color:var(--warn)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>IA Operator Bridge</h1><p class="muted">Primeiro loop seguro: self-diagnosis → IA packets → vault refs ou popup móvel → importação → tarefas.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/mobile-permission-relay'" class="dark">Permissões</button><button onclick="location.href='/app/god-mode-vault'" class="dark">Vault</button><button onclick="dashboard()">Dashboard</button></div></section><section class="panel"><h2>Arrancar loop autónomo</h2><textarea id="goal">Deixar o God Mode instalável, utilizável no PC e capaz de continuar trabalho com IAs, permissões móveis e vault.</textarea><button onclick="startLoop()">Start first autonomous work loop</button></section><section class="panel"><h2>Continuar packet com nota/resposta</h2><input id="packetId" style="width:100%" placeholder="ia-work-packet-..."/><textarea id="noteText">Cole aqui a resposta/nota capturada do provider.</textarea><button onclick="continueNote()">Importar e converter</button></section><section class="panel"><h2>Loops / bindings</h2><div id="items" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const items=x?.packet_bindings||x?.autonomous_loops||x?.dashboard?.packet_bindings||[];qs('#items').innerHTML=(Array.isArray(items)?items:[]).slice(0,30).map(it=>`<div class="item ${it.status==='permission_required'?'wait':''}"><b>${esc(it.status)}</b><br>${esc(it.work_packet_id||it.autonomous_loop_id)}<br><span class="muted">${esc(it.provider||it.goal||'')}</span></div>`).join('')}async function dashboard(){show(await api('/api/ia-operator-bridge/dashboard'))}async function startLoop(){show(await api('/api/ia-operator-bridge/start-loop',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({goal:qs('#goal').value,project_id:'GOD_MODE',providers:['chatgpt','claude','gemini']})}))}async function continueNote(){show(await api('/api/ia-operator-bridge/continue-with-note',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_packet_id:qs('#packetId').value,note_text:qs('#noteText').value,provider:'manual_ai'})}))}dashboard()</script></body></html>
"""


@router.get('/app/ia-operator-bridge', response_class=HTMLResponse)
async def ia_operator_bridge_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/first-autonomous-work-loop', response_class=HTMLResponse)
async def first_autonomous_work_loop_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
